  ('pukao-0a2fc18c-moex-00286', 'pukao-0a2fc18c', 'pukao-0a2fc18c-moex-110-6948958a', 'sub-pukao-0a2fc18c-02', NULL, 'single_choice', '由於國家公園的遊客過多，導致生態環境惡化，野生動、植物都大量減少。為解決以上的困境，請問下列 何種方案較可能有效的解決國家公園所面臨的問題？', '["降低遊憩設施的舒適程度", "增加野生動植物的野放與種植", "提高國家公園的門票價格", "減少國家公園的管理人員以及設施維護"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:11+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "419", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "經建行政"}'::jsonb, NULL),
  ('pukao-0a2fc18c-moex-00287', 'pukao-0a2fc18c', 'pukao-0a2fc18c-moex-110-6948958a', 'sub-pukao-0a2fc18c-02', NULL, 'single_choice', '需求拉動型通貨膨脹將造成：', '["物價水準提升但不改變實質GDP", "同時使物價水準及實質GDP提升", "物價水準提升但降低實質GDP", "總合供給曲線（aggregatesupplycurve）向右移動"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:11+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "419", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "經建行政"}'::jsonb, NULL),
